mapper.select:
SELECT MAX(bill_ym)
FROM bill
WHERE ho_no = #{hoNo}

SELECT
       #{billYm} AS billYm,
       (
           SELECT b.bill_no
           FROM bill b
           WHERE b.ho_no = #{hoNo}
             AND b.bill_ym = #{billYm}
           FETCH FIRST 1 ROWS ONLY
       ) AS billNo,
       NVL((
           SELECT b.bill_tot_amt
           FROM bill b
           WHERE b.ho_no = #{hoNo}
             AND b.bill_ym = #{billYm}
           FETCH FIRST 1 ROWS ONLY
       ), 0) AS currentBillAmt,
       NVL((
           SELECT b.bill_tot_amt
           FROM bill b
           WHERE b.ho_no = #{hoNo}
             AND b.bill_ym = TO_CHAR(ADD_MONTHS(TO_DATE(#{billYm}, 'YYYYMM'), -1), 'YYYYMM')
           FETCH FIRST 1 ROWS ONLY
       ), 0) AS previousBillAmt,
       NVL((
           SELECT ROUND(AVG(b.bill_tot_amt), 0)
           FROM bill b
                INNER JOIN apt_detail ad ON ad.ho_no = b.ho_no
                INNER JOIN apt_unit au ON au.dong_no = ad.dong_no
           WHERE au.apt_cmplex_no = #{aptCmplexNo}
             AND b.bill_ym = #{billYm}
       ), 0) AS similarAvgAmt
FROM dual
